package org.apache.commons.csv;
import static org.apache.commons.csv.Token.Type.TOKEN;
import java.io.File;
import java.io.FileReader;
import java.io.InputStreamReader;
import java.io.Reader;
import java.io.StringReader;
import java.net.URL;
import java.nio.charset.Charset;
import java.util.ArrayList;
import java.util.Iterator;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.NoSuchElementException;

import static org.mockito.Mockito.*;

import java.io.Closeable;
import java.io.IOException;
import java.lang.reflect.Field;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import static org.junit.jupiter.api.Assertions.*;

class CSVParserTest {

    private CSVParser csvParser;
    private Closeable mockLexer;

    @BeforeEach
    void setUp() throws Exception {
        // Create a partial mock of CSVParser with a real constructor
        csvParser = Mockito.mock(CSVParser.class, Mockito.withSettings()
                .useConstructor((java.io.Reader) null, (CSVFormat) null)
                .defaultAnswer(Mockito.CALLS_REAL_METHODS));
        // Create a mock lexer (Closeable)
        mockLexer = mock(Closeable.class);

        // Use reflection to set the private lexer field
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, mockLexer);
    }

    @Test
    void close_whenLexerIsNotNull_shouldCallLexerClose() throws IOException {
        csvParser.close();
        verify(mockLexer, times(1)).close();
    }

    @Test
    void close_whenLexerIsNull_shouldNotThrow() throws IOException, NoSuchFieldException, IllegalAccessException {
        // Set lexer field to null via reflection
        Field lexerField = CSVParser.class.getDeclaredField("lexer");
        lexerField.setAccessible(true);
        lexerField.set(csvParser, null);

        assertDoesNotThrow(() -> csvParser.close());
    }

}
